<?php namespace App\Http\Controllers\Inventory; use App\Http\Controllers\Controller; use App\Services\Inventory\StockService; use Illuminate\Http\JsonResponse; class StockController extends Controller { public function __construct(private StockService $service) {} public function addStock($req): JsonResponse { $this->service->addStock($req->item_id, $req->store_id, $req->qty, $req->reason); return response()->json(['status' => 'ok']); } }
